#!/bin/bash
# gen-slurm-conf.sh — Auto-detect system parameters and write slurm.conf + cgroup.conf
# Usage: bash gen-slurm-conf.sh [--sysconfdir /etc/slurm] [--prefix /usr/local/slurm]
# Reads live system values (IP, CPUs, RAM) — no manual editing needed
set -euo pipefail

PREFIX=${PREFIX:-/usr/local/slurm}
SYSCONFDIR=${SYSCONFDIR:-/etc/slurm}
SLURM_STATE=${SLURM_STATE:-/var/lib/slurm}
SLURM_SPOOL=${SLURM_SPOOL:-/tmp/slurmd}

while [[ $# -gt 0 ]]; do
  case $1 in
    --sysconfdir) SYSCONFDIR="$2"; shift 2 ;;
    --prefix) PREFIX="$2"; shift 2 ;;
    --state) SLURM_STATE="$2"; shift 2 ;;
    --dry-run) DRY_RUN=1; shift ;;
    *) echo "Unknown: $1"; exit 1 ;;
  esac
done

# Auto-detect
NODE_NAME=$(hostname -s)
# Prefer the LAN IP (not routed external IPs that may be firewalled)
NODE_IP=$(ip addr show | awk '/inet / && !/127\.0\.0\.1/{print $2}' | cut -d/ -f1 | head -1)
NODE_CPUS=$(nproc)
NODE_MEM=$(( $(free -m | awk '/Mem:/{print $2}') - 600 ))

echo "Detected system parameters:"
echo "  Hostname : $NODE_NAME"
echo "  LAN IP   : $NODE_IP"
echo "  CPUs     : $NODE_CPUS"
echo "  RAM (MB) : $NODE_MEM  ($(free -m | awk '/Mem:/{print $2}') minus 600 headroom)"
echo "  Conf dir : $SYSCONFDIR"
echo ""

if [[ "${DRY_RUN:-0}" == "1" ]]; then
  echo "(dry-run — files not written)"
  exit 0
fi

mkdir -p "$SYSCONFDIR" "$SLURM_STATE" "$SLURM_SPOOL"
chown slurm:slurm "$SYSCONFDIR" "$SLURM_STATE" 2>/dev/null || true

# ── cgroup.conf ──────────────────────────────────────────────────────────────
cat > "$SYSCONFDIR/cgroup.conf" << 'EOF'
# Slurm cgroup config for DMR BKC systems
# cgroup/v2 is not mounted on the custom 6.18.x BKC kernel — use v1
# Constraints are off; process tracking is done via proctrack/linuxproc instead
CgroupPlugin=cgroup/v1
ConstrainCores=no
ConstrainDevices=no
ConstrainRAMSpace=no
ConstrainSwapSpace=no
EOF

echo "Wrote: $SYSCONFDIR/cgroup.conf"

# ── slurm.conf ───────────────────────────────────────────────────────────────
cat > "$SYSCONFDIR/slurm.conf" << EOF
# Slurm Configuration — Single-Node DMR Rack System
# Auto-generated by gen-slurm-conf.sh on $(date)
# System: ${NODE_NAME} (${NODE_IP}), ${NODE_CPUS} CPUs, ${NODE_MEM} MB RAM

ClusterName=dmr-testbed
# SlurmctldHost syntax: hostname(IP) — forces LAN IP, avoids external DNS resolution
SlurmctldHost=${NODE_NAME}(${NODE_IP})

SlurmUser=slurm
SlurmctldPort=6817
SlurmdPort=6818
AuthType=auth/munge
StateSaveLocation=${SLURM_STATE}
SlurmdSpoolDir=${SLURM_SPOOL}

# ── Scheduling ──
SchedulerType=sched/backfill
SelectType=select/linear

# task/none and jobacct_gather/none: disable cgroup-dependent plugins
# Required on BKC kernels where cgroup namespaces (cpuset, freezer) are not mounted
TaskPlugin=task/none
JobAcctGatherType=jobacct_gather/none

# proctrack/linuxproc: process tracking via /proc — no cgroups needed
ProctrackType=proctrack/linuxproc

# ── Node definition ──
# NodeAddr must be the IP that slurmctld and clients can reach slurmd on.
# On DMR systems: hostname may resolve to a firewalled external IP (172.25.x.x)
# but LAN IP (10.3.x.x) is the reachable address.
NodeName=${NODE_NAME} NodeAddr=${NODE_IP} \\
    CPUs=${NODE_CPUS} Sockets=1 CoresPerSocket=${NODE_CPUS} ThreadsPerCore=1 \\
    RealMemory=${NODE_MEM}

# ── Partitions ──
# 4 partitions sharing one node — allows scheduling simulation and workload isolation:
#   batch (default) : general purpose, unlimited time
#   debug           : short jobs / testing, 30 min limit, Priority wins over batch
#   fast            : very fast turnaround, 10 min limit, highest priority
#   long            : background/long jobs, 7 day limit, lowest priority
PartitionName=batch Nodes=${NODE_NAME} MaxTime=UNLIMITED  Priority=1 Default=YES
PartitionName=debug Nodes=${NODE_NAME} MaxTime=00:30:00   Priority=2
PartitionName=fast  Nodes=${NODE_NAME} MaxTime=00:10:00   Priority=3
PartitionName=long  Nodes=${NODE_NAME} MaxTime=7-00:00:00 Priority=0

PriorityType=priority/basic
EOF

echo "Wrote: $SYSCONFDIR/slurm.conf"
echo ""
echo "Next steps:"
echo "  1. Start daemons:  bash scripts/slurm-start.sh --clean"
echo "  2. Verify:         sinfo --long"
echo "  3. Test jobs:      bash scripts/slurm-test-jobs.sh"
